import{_ as e,o as r,c as o,ai as s,u2 as n,u3 as t,u4 as c,u5 as i,u6 as p,u7 as d,u8 as l}from"./chunks/framework.DIUhWiTt.js";const h=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"notas/PortSwigger/5.Authentication vulnerabilities/12.Password brute-force via password change/12.Password brute-force via password change.md","filePath":"notas/PortSwigger/5.Authentication vulnerabilities/12.Password brute-force via password change/12.Password brute-force via password change.md"}'),u={name:"notas/PortSwigger/5.Authentication vulnerabilities/12.Password brute-force via password change/12.Password brute-force via password change.md"};function m(_,a,g,b,v,w){return r(),o("div",null,[...a[0]||(a[0]=[s('<p>Normalmente, el cambio de contraseña implica introducir la contraseña actual y, a continuación, la nueva contraseña dos veces. Estas páginas se basan fundamentalmente en el mismo proceso para comprobar que los nombres de usuario y las contraseñas actuales coinciden que una página de inicio de sesión normal. Por lo tanto, estas páginas pueden ser vulnerables a las mismas técnicas.</p><p>La funcionalidad de cambio de contraseña puede ser especialmente peligrosa si permite a un atacante acceder a ella directamente sin haber iniciado sesión como el usuario víctima. Por ejemplo, si el nombre de usuario se proporciona en un campo oculto, un atacante podría ser capaz de editar este valor en la solicitud para dirigirse a usuarios arbitrarios. Esto puede ser potencialmente explotado para enumerar nombres de usuario y contraseñas de fuerza bruta.</p><p><img src="'+n+'" alt="20250807214352.png"></p><p>Al ingresar con las credenciales del usuario <code>wiener</code> y al ir en nuestra cuenta observamos que podemos cambiar nuestra contraseña, pero proporcionando la contraseña actual.</p><p><img src="'+t+'" alt="20250807224859.png"></p><p>En el primer caso si la contraseña actual es la correcta pero la nueva difieren te da un mensaje de <code>New password do not match</code></p><p><img src="'+c+'" alt="20250807224926.png"></p><p>en caso de que la contraseña actual sea incorrecta y las otras hagan <code>match</code> este te llevara al login principal</p><p><img src="'+i+'" alt="20250807225119.png"></p><p>Teniendo esto en cuenta e interceptando la solicitud de cambio de contraseña y cambiamos el nombre de usuario de <code>wiener</code> a <code>carlos</code> para luego hacer un ataque del tipo <code>snniper</code> y asi hacer un brute force para encontrar la contraseña correcta</p><p><img src="'+p+'" alt="20250807224957.png"></p><p>Luego de enviar el ataque encontraremos que la contraseña para el usuario <code>carlos</code> es <code>131313</code></p><p><img src="'+d+'" alt="20250807225021.png"></p><p><img src="'+l+'" alt="20250807225144.png"></p>',14)])])}const P=e(u,[["render",m]]);export{h as __pageData,P as default};
